\begin{align*}
\log_{10}{4}+2\log_{10}{5}+3\log_{10}{2}+6\log_{10}{5}+\log_{10}{8} &= \log_{10}{4}+\log_{10}{5^2}+\log_{10}{2^3}+\log_{10}{8}\\
&= \log_{10}{4}+\log_{10}{25}+\log_{10}{8}+\log_{10}{8}\\
&= \log_{10}{(4\times 25\times 8\times 8)}\\
&= \log_{10}{5120}
\end{align*}
